<template>
	<u-keyboard v-model="showKeyboard" ref="uKeyboard" mode="number" :mask="true" tips="请输入交易密码"
		:mask-close-able="false" @change="keyChange" @backspace="backspaceClick" @confirm="keyConfirm"
		@cancel="keyCancel">
		<template #default>
			<u-message-input mode="bottomLine" :maxlength="len" :focus="true" :dot-fill="true" :disabled-keyboard="true"
				:value="inputValue"></u-message-input>
		</template>
	</u-keyboard>
</template>

<script>
	export default {
		name: "password-input",
		props: {
			popupShow: {
				type: Boolean,
				default: false
			},
		},
		watch: {
			popupShow: {
				handler(nv) {
					this.showKeyboard = this.popupShow
				},
			},
			showKeyboard(nv) {
				if (nv == false) {
					this.inputValue = ''
				}
			}
		},
		data() {
			return {
				showKeyboard: false,
				inputValue: "",
				len: 6,
			};
		},
		methods: {
			keyChange(e) {
				if (this.inputValue.length >= this.len)
					return
				else {
					this.inputValue += e
					if (this.inputValue.length == this.len) {
						this.$emit('ok', this.inputValue)
						this.$emit('update:popup-show', false)
					}
				}
			},
			backspaceClick() {
				if (this.inputValue.length) {
					this.inputValue = this.inputValue.substring(0, this.inputValue.length - 1)
				}
			},
			keyConfirm(e) {
				this.$emit('ok', this.inputValue)
				this.$emit('update:popup-show', false)
			},
			keyCancel() {
				this.$emit('close', this.inputValue)
				this.$emit('update:popup-show', false)
			},
		}
	}
</script>

